import { useEffect, useRef } from "react";
import maplibregl from "maplibre-gl";
import "maplibre-gl/dist/maplibre-gl.css";
import { X, Crosshair, Maximize2 } from "lucide-react";
import type { ConflictZone } from "../types";

interface Props {
  zone: ConflictZone;
  onClose: () => void;
}

export default function DetailMap({ zone, onClose }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<maplibregl.Map | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    // Small delay to ensure the container is rendered and has dimensions
    const timer = setTimeout(() => {
      if (!containerRef.current) return;

      const map = new maplibregl.Map({
        container: containerRef.current,
        style: {
          version: 8,
          sources: {
            esri: {
              type: "raster",
              tiles: [
                "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}",
              ],
              tileSize: 256,
              attribution: "© Esri",
            },
            labels: {
              type: "raster",
              tiles: [
                "https://basemaps.cartocdn.com/dark_only_labels/{z}/{x}/{y}@2x.png",
              ],
              tileSize: 256,
            },
          },
          layers: [
            {
              id: "esri-sat",
              type: "raster",
              source: "esri",
              paint: {
                "raster-saturation": -1,
                "raster-contrast": 0.2,
                "raster-brightness-max": 0.85,
              },
            },
            {
              id: "labels",
              type: "raster",
              source: "labels",
              paint: { "raster-opacity": 0.7 },
            },
          ],
        },
        center: [zone.lon, zone.lat],
        zoom: zone.zoom + 1,
        maxZoom: 18,
      });

      map.addControl(
        new maplibregl.NavigationControl({ showCompass: true }),
        "bottom-right"
      );

      // Add zone marker
      const el = document.createElement("div");
      el.style.width = "22px";
      el.style.height = "22px";
      el.style.borderRadius = "50%";
      el.style.background = zone.color;
      el.style.border = "2px solid rgba(0,0,0,0.6)";
      el.style.boxShadow = `0 0 16px ${zone.color}80`;

      new maplibregl.Marker({ element: el })
        .setLngLat([zone.lon, zone.lat])
        .addTo(map);

      // Pulse ring
      const ring = document.createElement("div");
      ring.style.width = "40px";
      ring.style.height = "40px";
      ring.style.borderRadius = "50%";
      ring.style.border = `2px solid ${zone.color}`;
      ring.style.opacity = "0.4";
      ring.style.animation = "ping 2s cubic-bezier(0, 0, 0.2, 1) infinite";
      ring.style.position = "absolute";
      ring.style.top = "-9px";
      ring.style.left = "-9px";
      ring.style.pointerEvents = "none";
      el.appendChild(ring);

      mapRef.current = map;

      // Force resize after mount
      setTimeout(() => map.resize(), 100);
    }, 50);

    return () => {
      clearTimeout(timer);
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, [zone]);

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        display: "flex",
        flexDirection: "column",
        background: "rgba(9,9,11,0.97)",
      }}
    >
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "10px 16px",
          borderBottom: "1px solid rgba(63,63,70,0.5)",
          flexShrink: 0,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <div
            style={{
              width: 12,
              height: 12,
              borderRadius: "50%",
              background: zone.color,
              boxShadow: `0 0 10px ${zone.color}60`,
            }}
          />
          <div>
            <div
              style={{
                color: "#f4f4f5",
                fontSize: "14px",
                fontWeight: 600,
              }}
            >
              {zone.name}
            </div>
            <div style={{ color: "#71717a", fontSize: "10px" }}>
              {zone.conflict} · {zone.region} · {zone.lat.toFixed(2)}°,{" "}
              {zone.lon.toFixed(2)}°
            </div>
          </div>
        </div>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onClose();
          }}
          style={{
            color: "#a1a1aa",
            fontSize: "12px",
            padding: "6px 14px",
            border: "1px solid rgba(63,63,70,0.7)",
            background: "rgba(39,39,42,0.4)",
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            gap: "6px",
            transition: "all 0.15s",
          }}
          onMouseEnter={(e) => {
