            e.currentTarget.style.color = "#f4f4f5";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.borderColor = "rgba(63,63,70,0.7)";
            e.currentTarget.style.color = "#a1a1aa";
          }}
        >
          <X size={14} /> Close
        </button>
      </div>

      {/* Map container - takes remaining space */}
      <div style={{ flex: 1, position: "relative", minHeight: 0 }}>
        <div
          ref={containerRef}
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
          }}
        />
        {/* Scan lines overlay on expanded map */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            pointerEvents: "none",
            opacity: 0.03,
            backgroundImage:
              "repeating-linear-gradient(0deg, transparent, transparent 1px, rgba(255,255,255,0.1) 1px, rgba(255,255,255,0.1) 2px)",
            backgroundSize: "100% 3px",
            zIndex: 2,
          }}
        />
        {/* Crosshair overlay */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            pointerEvents: "none",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 3,
          }}
        >
          <Crosshair
            size={32}
            style={{ color: "rgba(239,68,68,0.25)" }}
          />
        </div>
      </div>

      {/* Info bar */}
      <div
        style={{
          padding: "8px 16px",
          borderTop: "1px solid rgba(63,63,70,0.4)",
          fontSize: "10px",
          color: "#71717a",
          flexShrink: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <span>
          <span style={{ color: "#a1a1aa" }}>{zone.description}</span>
          <span style={{ marginLeft: 8 }}>
            · Last event: {zone.lastEvent}
          </span>
        </span>
        <span style={{ display: "flex", alignItems: "center", gap: 4 }}>
          <Maximize2 size={10} />
          Scroll to zoom · Drag to pan
        </span>
      </div>

      {/* Ping animation keyframes */}
      <style>{`
        @keyframes ping {
          75%, 100% {
            transform: scale(2);
            opacity: 0;
          }
        }
      `}</style>
    </div>
  );
}

